# Phase 1 Component Tests

## Purpose

Test each shared component in isolation BEFORE building pages that depend on them.

## Code is Functional WHEN...

### Modal Component Tests

```javascript
// tests/components/modal.test.js
describe("Modal", () => {
  it("opens when trigger clicked", () => {
    click("[data-modal-target=test-modal]");
    expect("[data-modal=test-modal]").toBeVisible();
  });

  it("closes on backdrop click", () => {
    Modal.open("test-modal");
    click(".modal-backdrop");
    expect("[data-modal=test-modal]").not.toBeVisible();
  });

  it("closes on Escape key", () => {
    Modal.open("test-modal");
    pressKey("Escape");
    expect("[data-modal=test-modal]").not.toBeVisible();
  });

  it("traps focus inside modal", () => {
    Modal.open("test-modal");
    expect(document.activeElement).toBeInsideElement("[data-modal=test-modal]");
    pressKey("Tab");
    expect(document.activeElement).toBeInsideElement("[data-modal=test-modal]");
  });

  it("returns focus to trigger on close", () => {
    const trigger = document.querySelector("[data-modal-target=test-modal]");
    trigger.click();
    Modal.close("test-modal");
    expect(document.activeElement).toBe(trigger);
  });
});
```

