# Create Shared JS Components

Build the core interactive components used throughout the mockups. These must be vanilla JS (no React) and fully accessible.

## Components to Build

### 1. Modal Component (`modal.js`)

```javascript
// Usage:
// <button data-modal-trigger="create-org">Open Modal</button>
// <div data-modal="create-org" class="hidden">...</div>

class Modal {
  constructor(element) {
    this.modal = element;
    this.id = element.dataset.modal;
    this.triggers = document.querySelectorAll(`[data-modal-trigger="${this.id}"]`);
    this.closeButtons = element.querySelectorAll('[data-modal-close]');
    this.previousFocus = null;
    this.init();
  }

  init() {
    // Add ARIA attributes
    this.modal.setAttribute('role', 'dialog');
    this.modal.setAttribute('aria-modal', 'true');

    // Bind triggers
    this.triggers.forEach(trigger => {
      trigger.addEventListener('click', () => this.open());
    });

    // Bind close buttons
    this.closeButtons.forEach(btn => {
      btn.addEventListener('click', () => this.close());
    });

    // Close on Escape
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && this.isOpen()) this.close();
    });

    // Close on backdrop click
    this.modal.addEventListener('click', (e) => {
      if (e.target === this.modal) this.close();
    });
  }

  open() {
    this.previousFocus = document.activeElement;
    this.modal.classList.remove('hidden');
    this.trapFocus();
    this.modal.querySelector('[data-modal-focus]')?.focus();
  }

  close() {
    this.modal.classList.add('hidden');
    this.previousFocus?.focus();
  }

  trapFocus() {
    // Focus trap implementation
  }

  isOpen() {
    return !this.modal.classList.contains('hidden');
  }
}

// Auto-init all modals
document.querySelectorAll('[data-modal]').forEach(el => new Modal(el));
```

**Accessibility Requirements:**
