### 2. Dropdown Component (`dropdown.js`)

```javascript
// Usage:
// <div data-dropdown>
//   <button data-dropdown-trigger>Menu</button>
//   <div data-dropdown-content class="hidden">...</div>
// </div>

class Dropdown {
  constructor(element) {
    this.container = element;
    this.trigger = element.querySelector('[data-dropdown-trigger]');
    this.content = element.querySelector('[data-dropdown-content]');
    this.init();
  }

  init() {
    this.trigger.setAttribute('aria-expanded', 'false');
    this.trigger.setAttribute('aria-haspopup', 'true');

    this.trigger.addEventListener('click', () => this.toggle());

    // Close on outside click
    document.addEventListener('click', (e) => {
      if (!this.container.contains(e.target)) this.close();
    });

    // Escape closes
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && this.isOpen()) this.close();
    });
  }

  toggle() {
    this.isOpen() ? this.close() : this.open();
  }

  open() {
    this.content.classList.remove('hidden');
    this.trigger.setAttribute('aria-expanded', 'true');
  }

  close() {
    this.content.classList.add('hidden');
    this.trigger.setAttribute('aria-expanded', 'false');
  }

  isOpen() {
    return !this.content.classList.contains('hidden');
  }
}
```

### 3. Tabs Component (`tabs.js`)

```javascript
// Usage:
// <div data-tabs>
//   <div data-tabs-list role="tablist">
//     <button data-tab="overview" role="tab">Overview</button>
//     <button data-tab="licenses" role="tab">Licenses</button>
//   </div>
//   <div data-tab-content="overview" role="tabpanel">...</div>
//   <div data-tab-content="licenses" role="tabpanel" hidden>...</div>
// </div>

class Tabs {
  constructor(element) {
    this.container = element;
    this.tabs = element.querySelectorAll('[data-tab]');
    this.panels = element.querySelectorAll('[data-tab-content]');
    this.init();
  }

  init() {
    this.tabs.forEach(tab => {
      tab.addEventListener('click', () => this.activate(tab.dataset.tab));
    });

    // Arrow key navigation
    this.container.addEventListener('keydown', (e) => {
      if (['ArrowLeft', 'ArrowRight'].includes(e.key)) {
        this.handleArrowKey(e);
      }
    });
  }

  activate(tabId) {
    this.tabs.forEach(tab => {
      const isActive = tab.dataset.tab === tabId;
      tab.setAttribute('aria-selected', isActive);
      tab.classList.toggle('border-b-2', isActive);
    });

    this.panels.forEach(panel => {
      panel.hidden = panel.dataset.tabContent !== tabId;
    });
  }
}
```

### 4. Toast Component (`toast.js`)

```javascript
// Usage: showToast('User created successfully', 'success');

const toastContainer = document.createElement('div');
toastContainer.className = 'fixed bottom-4 right-4 z-50 flex flex-col gap-2';
document.body.appendChild(toastContainer);

export function showToast(message, type = 'info', duration = 5000) {
  const toast = document.createElement('div');
  toast.className = `px-4 py-3 rounded-lg shadow-lg text-white ${getToastColor(type)}`;
  toast.setAttribute('role', 'alert');
  toast.setAttribute('aria-live', 'polite');
  toast.textContent = message;

  toastContainer.appendChild(toast);

  // Auto-dismiss
  setTimeout(() => {
    toast.classList.add('opacity-0', 'transition-opacity');
    setTimeout(() => toast.remove(), 300);
  }, duration);
}

function getToastColor(type) {
  const colors = {
    success: 'bg-green-600',
    error: 'bg-red-600',
    warning: 'bg-yellow-600',
    info: 'bg-blue-600'
  };
  return colors[type] || colors.info;
}
```

