import { Modal } from './components/modal.js';

class CommandPalette {
  constructor() {
    this.createDOM();
    this.bindShortcut();
    this.initSearch();
  }

  createDOM() {
    const html = `
      <div data-command-palette class="hidden fixed inset-0 z-50 bg-black/50 flex items-start justify-center pt-[20vh]">
        <div class="w-full max-w-xl bg-white rounded-xl shadow-2xl overflow-hidden">
          <div class="p-4 border-b">
            <input 
              type="text" 
              placeholder="Search or jump to..."
              class="w-full text-lg outline-none"
              data-command-input
            >
          </div>
          <div class="max-h-80 overflow-y-auto" data-command-results>
            <!-- Results populated dynamically -->
          </div>
          <div class="p-2 border-t bg-slate-50 text-xs text-slate-500 flex gap-4">
            <span><kbd class="px-1.5 py-0.5 bg-white border rounded">↵</kbd> to select</span>
            <span><kbd class="px-1.5 py-0.5 bg-white border rounded">↑↓</kbd> to navigate</span>
            <span><kbd class="px-1.5 py-0.5 bg-white border rounded">esc</kbd> to close</span>
          </div>
        </div>
      </div>
    `;
    document.body.insertAdjacentHTML('beforeend', html);

    this.overlay = document.querySelector('[data-command-palette]');
    this.input = document.querySelector('[data-command-input]');
    this.results = document.querySelector('[data-command-results]');
  }

  bindShortcut() {
    document.addEventListener('keydown', (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        this.open();
      }
      if (e.key === 'Escape' && this.isOpen()) {
        this.close();
      }
    });
  }

  open() {
    this.overlay.classList.remove('hidden');
    this.input.value = '';
    this.input.focus();
    this.renderResults('');
  }

  close() {
    this.overlay.classList.add('hidden');
  }

  isOpen() {
    return !this.overlay.classList.contains('hidden');
  }

  initSearch() {
    this.input.addEventListener('input', (e) => {
      this.renderResults(e.target.value);
    });

    // Keyboard navigation
    this.input.addEventListener('keydown', (e) => {
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        this.selectNext();
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        this.selectPrev();
      } else if (e.key === 'Enter') {
        e.preventDefault();
        this.executeSelected();
      }
    });
  }

  renderResults(query) {
    const items = this.getItems(query);
    this.results.innerHTML = items.map((item, i) => `
      <a href="${item.url}" 
         class="block px-4 py-3 hover:bg-slate-100 ${i === 0 ? 'bg-slate-100' : ''}"
         data-command-item="${i}">
        <div class="flex items-center gap-3">
          <i data-lucide="${item.icon}" class="w-5 h-5 text-slate-400"></i>
          <div>
            <div class="font-medium">${item.title}</div>
            <div class="text-sm text-slate-500">${item.category}</div>
          </div>
        </div>
