Create the bell icon notification dropdown that appears in both Admin and Portal headers.

## Notification Types

| Type | Icon | Color | Example |
|------|------|-------|---------|
| alert | alert-circle | Red | License expiring, payment failed |
| update | info | Blue | New user added, seat assigned |
| system | megaphone | Purple | Feature announcement, maintenance |

## Implementation

Create `src/shared/js/notifications.js`:

```javascript
import { Dropdown } from './components/dropdown.js';
import { storage } from './state.js';

class NotificationCenter {
  constructor() {
    this.notifications = storage.get('notifications') || [];
    this.createDOM();
    this.bindEvents();
    this.updateBadge();
  }

  createDOM() {
    // Notification dropdown HTML is in the header partial
    this.bell = document.querySelector('[data-notification-bell]');
    this.dropdown = document.querySelector('[data-notification-dropdown]');
    this.list = document.querySelector('[data-notification-list]');
    this.badge = document.querySelector('[data-notification-badge]');

    if (!this.bell) return;

    this.render();
  }

  render() {
    const unread = this.notifications.filter(n => !n.read);
    const read = this.notifications.filter(n => n.read);

    this.list.innerHTML = `
      ${unread.length ? `
        <div class="px-4 py-2 text-xs font-semibold text-slate-500 uppercase">
          New (${unread.length})
        </div>
        ${unread.map(n => this.renderItem(n)).join('')}
      ` : ''}

      ${read.length ? `
        <div class="px-4 py-2 text-xs font-semibold text-slate-500 uppercase border-t">
          Earlier
        </div>
        ${read.slice(0, 5).map(n => this.renderItem(n)).join('')}
      ` : ''}

      ${!this.notifications.length ? `
        <div class="px-4 py-8 text-center text-slate-500">
          <i data-lucide="bell-off" class="w-8 h-8 mx-auto mb-2 opacity-50"></i>
          <p>No notifications</p>
        </div>
      ` : ''}
    `;

    // Refresh icons
    if (window.lucide) window.lucide.createIcons();
  }

  renderItem(notification) {
    const icons = {
      alert: 'alert-circle',
      update: 'info',
      system: 'megaphone'
    };
    const colors = {
      alert: 'text-red-500',
      update: 'text-blue-500',
      system: 'text-purple-500'
    };

    return `
      <a href="${notification.link}" 
         class="block px-4 py-3 hover:bg-slate-50 ${notification.read ? 'opacity-60' : ''}"
         data-notification-id="${notification.id}">
        <div class="flex gap-3">
          <i data-lucide="${icons[notification.type]}" 
             class="w-5 h-5 mt-0.5 ${colors[notification.type]}"></i>
          <div class="flex-1 min-w-0">
            <div class="font-medium text-sm">${notification.title}</div>
            <div class="text-xs text-slate-500 truncate">${notification.message}</div>
            <div class="text-xs text-slate-400 mt-1">${this.formatTime(notification.createdAt)}</div>
          </div>
          ${!notification.read ? `
            <div class="w-2 h-2 rounded-full bg-blue-500 mt-2"></div>
          ` : ''}
        </div>
      </a>
    `;
  }

  formatTime(isoString) {
    const date = new Date(isoString);
    const now = new Date();
    const diffMs = now - date;
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffHours < 24) return `${diffHours}h ago`;
    if (diffDays < 7) return `${diffDays}d ago`;
    return date.toLocaleDateString();
  }

  updateBadge() {
    const unreadCount = this.notifications.filter(n => !n.read).length;
    if (this.badge) {
      this.badge.textContent = unreadCount;
      this.badge.classList.toggle('hidden', unreadCount === 0);
    }
  }

  bindEvents() {
    // Mark as read when clicking notification
    this.list?.addEventListener('click', (e) => {
      const item = e.target.closest('[data-notification-id]');
      if (item) {
        this.markAsRead(item.dataset.notificationId);
      }
    });

    // Mark all as read button
    document.querySelector('[data-mark-all-read]')?.addEventListener('click', () => {
      this.markAllAsRead();
    });
  }

  markAsRead(id) {
    const notification = this.notifications.find(n => n.id === id);
    if (notification) {
      notification.read = true;
      storage.set('notifications', this.notifications);
      this.updateBadge();
    }
  }

  markAllAsRead() {
    this.notifications.forEach(n => n.read = true);
    storage.set('notifications', this.notifications);
    this.render();
    this.updateBadge();
  }
}

// Initialize when DOM ready
document.addEventListener('DOMContentLoaded', () => {
  new NotificationCenter();
});

export { NotificationCenter };
```

