# Set up LocalStorage State Management with Fallback

Create a centralized state management layer that persists demo data across pages and sessions. Includes fallback for private browsing mode.

## Why LocalStorage?

The mockups need to demonstrate:
- State persistence (assigned seats stay assigned)
- Cross-page consistency (notification count matches everywhere)
- Impersonation context (admin viewing as org)
- Table preferences (saved filters, column visibility)

Since there's no backend, LocalStorage simulates database persistence.

## Implementation

Create `src/shared/js/state.js`:

```javascript
/**
 * State Management with LocalStorage + Memory Fallback
 * 
 * Handles demo state persistence across pages. Falls back to in-memory
 * storage when LocalStorage is unavailable (private browsing).
 */

const STORAGE_PREFIX = 'crm_';
const memoryStore = {};

export const storage = {
  /**
   * Get value from storage
   * @param {string} key - Storage key (without prefix)
   * @returns {any} Parsed value or null
   */
  get(key) {
    try {
      const value = localStorage.getItem(STORAGE_PREFIX + key);
      return value ? JSON.parse(value) : null;
    } catch (e) {
      // LocalStorage unavailable (private browsing)
      return memoryStore[key] || null;
    }
  },

  /**
   * Set value in storage
   * @param {string} key - Storage key (without prefix)
   * @param {any} value - Value to store (will be JSON stringified)
   */
  set(key, value) {
    try {
      localStorage.setItem(STORAGE_PREFIX + key, JSON.stringify(value));
    } catch (e) {
      // LocalStorage unavailable
      memoryStore[key] = value;
    }
  },

  /**
   * Remove value from storage
   * @param {string} key - Storage key (without prefix)
   */
  remove(key) {
    try {
      localStorage.removeItem(STORAGE_PREFIX + key);
    } catch (e) {
      delete memoryStore[key];
    }
  },

  /**
   * Clear all CRM-prefixed storage
   */
  clear() {
    try {
      Object.keys(localStorage)
        .filter(k => k.startsWith(STORAGE_PREFIX))
        .forEach(k => localStorage.removeItem(k));
    } catch (e) {
      Object.keys(memoryStore).forEach(k => delete memoryStore[k]);
    }
  }
};

/**
 * Demo Scenario Loader
 * 
 * Loads different data sets based on URL param: ?scenario=<name>
 * - happy-path: Normal healthy data (default)
 * - at-risk: Expiring licenses, failed payments
 * - new-org: Empty states, onboarding visible
 * - large-data: 500+ rows for performance testing
 */
export function loadScenario() {
  const params = new URLSearchParams(window.location.search);
  const scenario = params.get('scenario') || 'happy-path';

  // Only load if not already loaded
  if (storage.get('_scenario') === scenario) return;

  console.log(`Loading scenario: ${scenario}`);

  // Clear existing data
  storage.clear();

  // Load scenario-specific data
  const dataPath = `/shared/data/${scenario}/`;

  Promise.all([
    fetch(`${dataPath}organizations.json`).then(r => r.json()),
    fetch(`${dataPath}licensePools.json`).then(r => r.json()),
    fetch(`${dataPath}users.json`).then(r => r.json()),
    fetch(`${dataPath}notifications.json`).then(r => r.json()),
  ]).then(([orgs, pools, users, notifs]) => {
    storage.set('organizations', orgs);
    storage.set('licensePools', pools);
    storage.set('users', users);
    storage.set('notifications', notifs);
    storage.set('_scenario', scenario);

    // Reload page to show new data
    window.location.reload();
  }).catch(err => {
    console.error('Failed to load scenario:', err);
  });
}

/**
 * Impersonation State
 * 
 * Tracks when admin is viewing the portal as a specific organization.
 */
export const impersonation = {
  get() {
    return storage.get('impersonation') || {
      active: false,
      orgId: null,
      orgName: null,
      startedAt: null
    };
  },

  start(orgId, orgName) {
    storage.set('impersonation', {
      active: true,
      orgId,
      orgName,
      startedAt: new Date().toISOString()
    });
    // Redirect to portal dashboard
    window.location.href = '/portal/index.html';
  },

  stop() {
    storage.set('impersonation', {
      active: false,
      orgId: null,
      orgName: null,
      startedAt: null
    });
    // Redirect back to admin
    window.location.href = '/admin/index.html';
  },

  isActive() {
    return this.get().active;
  }
};

/**
 * Table Preferences
 * 
 * Persists per-table settings: columns, filters, sort, density
 */
export function getTablePrefs(tableId) {
  return storage.get(`table_${tableId}`) || {
    columns: null, // null = show all
    filters: {},
    sort: { column: null, direction: 'asc' },
    density: 'comfortable' // comfortable | compact
  };
}

export function setTablePrefs(tableId, prefs) {
  storage.set(`table_${tableId}`, prefs);
}

// Initialize scenario on page load
document.addEventListener('DOMContentLoaded', () => {
  // Check URL for scenario param
  const params = new URLSearchParams(window.location.search);
  if (params.has('scenario')) {
    loadScenario();
  }

  // Initialize seed data if empty
  if (!storage.get('organizations')) {
    console.log('Initializing seed data...');
    // Will be populated by seed data loader
  }
});
